#include <vector>
#include <string>
using namespace std;

long long solve(string s) {
    int n = s.length();

    if (n == 0) return 0;

    vector<int> pre_L(n+1, 0);
    for (int i = 0; i < n; i++) {
        pre_L[i+1] = pre_L[i] + (s[i] == 'L' ? 1 : 0);
    }

    vector<int> suffix_T(n+1, 0);
    for (int i = n-1; i >= 0; i--) {
        suffix_T[i] = suffix_T[i+1] + (s[i] == 'T' ? 1 : 0);
    }

    long long base = 0;
    for (int i = 0; i < n; i++) {
        if (s[i] == 'C') {
            base += static_cast<long long>(pre_L[i]) * suffix_T[i+1];
        }
    }

    vector<long long> F(n+1, 0);
    F[n] = 0;
    for (int i = n-1; i >= 0; i--) {
        F[i] = F[i+1];
        if (s[i] == 'C') {
            F[i] += suffix_T[i+1];
        }
    }

    vector<long long> pre_LC(n+1, 0);
    for (int i = 0; i < n; i++) {
        pre_LC[i+1] = pre_LC[i];
        if (s[i] == 'C') {
            pre_LC[i+1] += pre_L[i];
        }
    }

    long long ans = base;

    for (int p = 0; p <= n; p++) {
        long long cand = base + F[p];
        if (cand > ans) {
            ans = cand;
        }

        cand = base + static_cast<long long>(pre_L[p]) * suffix_T[p];
        if (cand > ans) {
            ans = cand;
        }

        cand = base + pre_LC[p];
        if (cand > ans) {
            ans = cand;
        }
    }

    return ans;
}
```

### Explanation
1. **Base Count Calculation**: The base count is computed by iterating over each character in the string. For every 'C', we multiply the number of preceding 'L's (stored in `pre_L`) by the number of succeeding 'T's (stored in `suffix_T`), accumulating the result into `base`.

2. **Prefix and Suffix Arrays**: The `pre_L` array is built by traversing the string from left to right, counting 'L's up to each position. The `suffix_T` array is built by traversing the string from right to left, counting 'T's from each position to the end.

3. **CT Pairs Array (F)**: The `F` array is constructed by traversing the string from right to left. For each 'C', it adds the number of 'T's to the right (from `suffix_T`) to the existing count of "CT" pairs.

4. **LC Pairs Array (pre_LC)**: The `pre_LC` array is built by traversing the string from left to right. For each 'C', it adds the number of 'L's to the left (from `pre_L`) to the existing count of "LC" pairs.

5. **Maximizing Subsequences**: For each possible insertion position and letter ('L', 'C', 'T'), the solution evaluates the new count of "LCT" subsequences:
   - Inserting 'L' adds the number of "CT" pairs in the suffix starting at the insertion point.
   - Inserting 'C' adds the product of 'L's before and 'T's after the insertion point.
   - Inserting 'T' adds the number of "LC" pairs before the insertion point.

The maximum value obtained from these evaluations, including the base count, is returned as the result. This approach efficiently handles the constraints by leveraging prefix and suffix sums to avoid recalculating counts repeatedly.

