#include <vector>
#include <algorithm>
using namespace std;

long long solve(string s) {
    int n = s.length();

    long long L_count = 0, LC_count = 0, base = 0;
    for (char c : s) {
        if (c == 'L') {
            L_count++;
        } else if (c == 'C') {
            LC_count += L_count;
        } else if (c == 'T') {
            base += LC_count;
        }
    }

    vector<long long> prefixL(n+1, 0);
    vector<long long> prefixLC(n+1, 0);
    L_count = 0;
    LC_count = 0;
    for (int i = 0; i < n; i++) {
        if (s[i] == 'L') {
            L_count++;
        } else if (s[i] == 'C') {
            LC_count += L_count;
        }
        prefixL[i+1] = L_count;
        prefixLC[i+1] = LC_count;
    }

    vector<long long> suffixT(n+1, 0);
    vector<long long> suffixCT(n+1, 0);
    long long T = 0, CT = 0;
    for (int i = n-1; i >= 0; i--) {
        if (s[i]=='T') {
            T++;
        } else if (s[i]=='C') {
            CT += T;
        }
        suffixT[i] = T;
        suffixCT[i] = CT;
    }

    long long ans = base;
    for (int i = 0; i <= n; i++) {
        long long add1 = suffixCT[i];
        long long add2 = (long long)prefixL[i] * suffixT[i];
        long long add3 = prefixLC[i];
        long long max_add = max({add1, add2, add3});
        if (base + max_add > ans) {
            ans = base + max_add;
        }
    }

    return ans;
}
